  'v2/ru_speaker_4', 'v2/ru_speaker_5', 'v2/ru_speaker_6', 'v2/ru_speaker_7',
  'v2/ru_speaker_8', 'v2/ru_speaker_9',
  'v2/tr_speaker_0', 'v2/tr_speaker_1', 'v2/tr_speaker_2', 'v2/tr_speaker_3',
  'v2/tr_speaker_4', 'v2/tr_speaker_5', 'v2/tr_speaker_6', 'v2/tr_speaker_7',
  'v2/tr_speaker_8', 'v2/tr_speaker_9',
  'v2/zh_speaker_0', 'v2/zh_speaker_1', 'v2/zh_speaker_2', 'v2/zh_speaker_3',
  'v2/zh_speaker_4', 'v2/zh_speaker_5', 'v2/zh_speaker_6', 'v2/zh_speaker_7',
  'v2/zh_speaker_8', 'v2/zh_speaker_9'
];

const validFormats = ['wav', 'mp3', 'ogg', 'flac'];
const maxTextLength = 10000;

// Validation
if (!text) {
  return [{ json: { valid: false, error: 'text is required' } }];
}
if (text.length > maxTextLength) {
  return [{ json: { valid: false, error: 'text exceeds maximum length of ' + maxTextLength + ' characters' } }];
}
if (!validVoices.includes(voicePreset)) {
  return [{ json: { valid: false, error: 'Invalid voice_preset. Must be one of: ' + validVoices.slice(0, 5).join(', ') + ', ...' } }];
}
if (!validFormats.includes(outputFormat)) {
  return [{ json: { valid: false, error: 'Invalid output_format. Must be one of: ' + validFormats.join(', ') } }];
}

return [{
  json: {
    valid: true,
    text: text,
    voice_preset: voicePreset,
    output_format: outputFormat
  }
}];

// Decode base64 audio and save to file
const audioBase64 = $input.first().json.audio_base64;
const format = $input.first().json.format || 'wav';

if (!audioBase64) {
  return [{ json: { saved: false, error: 'No audio data received' } }];
}

const fs = require('fs');
const path = require('path');

// Whitelist allowed formats for filename extension
const validFormats = ['wav', 'mp3', 'ogg', 'flac'];
const sanitizedFormat = validFormats.includes(format) ? format : 'wav';

// Generate filename with timestamp - sanitize to prevent path traversal
const timestamp = new Date().toISOString().replace(/[:.]/g, '-').replace(/[^a-zA-Z0-9_-]/g, '');
const filename = `bark_${timestamp}.${sanitizedFormat}`;

// Path traversal protection - verify resolved path stays within output directory
const outputDir = '/data/bark/output';
const filepath = path.join(outputDir, filename);
const resolvedPath = path.resolve(filepath);
const resolvedOutputDir = path.resolve(outputDir);

if (!resolvedPath.startsWith(resolvedOutputDir + path.sep)) {
  return [{ json: { saved: false, error: 'Invalid filename: path traversal detected' } }];
}

// Ensure directory exists
if (!fs.existsSync(outputDir)) {
  fs.mkdirSync(outputDir, { recursive: true });
}

// Decode and save
const buffer = Buffer.from(audioBase64, 'base64');

// Enforce max file size (100MB)
const maxSizeBytes = 100 * 1024 * 1024;
if (buffer.length > maxSizeBytes) {
  return [{ json: { saved: false, error: 'Audio file exceeds maximum size of 100MB' } }];
}

fs.writeFileSync(filepath, buffer);

return [{
  json: {
    saved: true,
    filename: filename,
    filepath: filepath,
    size_bytes: buffer.length
  }
}];
